import React, { useState, useEffect, useRef } from 'react';
import { mysqlAPI } from '../services/mysqlApi';
import { Alert, Badge, EmptyState } from '../components/ui';
import ResultsPanel from '../components/ui/ResultsPanel';
import { Database, Send, Sparkles, CheckSquare, Square, ChevronDown, ChevronUp } from 'lucide-react';
import './ChatQueryPage.css';

const SAMPLES = [
  'Show all customers',
  'Show total orders by region',
  'Top 5 customers by total spend',
  'Show all confirmed orders',
  'Count orders by status',
  'Show orders joined with customer names',
  'Average order amount by region',
  'Show customers from North America',
];

export default function MySQLPage() {
  const [host, setHost]         = useState('127.0.0.1');
  const [port, setPort]         = useState(3307);
  const [database, setDatabase] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [tables, setTables]     = useState([]);
  const [selTables, setSelTables] = useState([]);
  const [showTables, setShowTables] = useState(true);
  const [connected, setConnected]   = useState(false);
  const [connecting, setConnecting] = useState(false);
  const [input, setInput]       = useState('');
  const [history, setHistory]   = useState([]);
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState('');
  const chatEndRef  = useRef(null);
  const textareaRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history, loading]);

  const handleConnect = async () => {
    if (!host || !database || !username || !password) {
      setError('Please fill in all connection fields.');
      return;
    }
    setConnecting(true);
    setError('');
    try {
      await mysqlAPI.testConnection({ host, port, database, username, password });
      const res = await mysqlAPI.listTables({ host, port, database, username, password });
      const tbls = res.data?.tables || [];
      setTables(tbls);
      setSelTables(tbls);
      setConnected(true);
    } catch (e) {
      setError(e.response?.data?.detail || 'Connection failed.');
    } finally {
      setConnecting(false);
    }
  };

  const handleDisconnect = () => {
    setConnected(false);
    setTables([]);
    setSelTables([]);
    setHistory([]);
    setError('');
  };

  const toggleTable = t =>
    setSelTables(p => p.includes(t) ? p.filter(x => x !== t) : [...p, t]);

  const toggleAll = () =>
    setSelTables(selTables.length === tables.length ? [] : [...tables]);

  const send = async () => {
    const q = input.trim();
    if (!q || loading) return;
    if (!connected) return setError('Connect to a MySQL database first.');
    setInput(''); setError('');
    setHistory(h => [...h, { type: 'user', content: q }]);
    setLoading(true);
    try {
      const endpoint = selTables.length > 1
        ? mysqlAPI.nlQueryJoin
        : mysqlAPI.nlQuery;
      const res = await endpoint({
        host, port, database, username, password,
        question: q,
        tables: selTables,
      });
      setHistory(h => [...h, {
        type: 'result',
        question: q,
        content: res.data,
      }]);
    } catch (e) {
      setHistory(h => [...h, {
        type: 'error',
        question: q,
        content: e.response?.data?.detail || 'Query failed.',
      }]);
    } finally {
      setLoading(false);
    }
  };

  const onKey = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); }
  };

  return (
    <div className="chat-query-page fade-in">

      {/* ── Left Panel ── */}
      <div className="cqp-left">

        {/* Connection Form */}
        <div className="cqp-section">
          <div className="cqp-section-label">MySQL Connection</div>

          {!connected ? (
            <>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                <input
                  className="cqp-select"
                  value={host}
                  onChange={e => setHost(e.target.value)}
                  placeholder="Host (127.0.0.1)"
                />
                <input
                  className="cqp-select"
                  value={port}
                  onChange={e => setPort(Number(e.target.value))}
                  placeholder="Port (3307)"
                  type="number"
                />
                <input
                  className="cqp-select"
                  value={database}
                  onChange={e => setDatabase(e.target.value)}
                  placeholder="Database name"
                />
                <input
                  className="cqp-select"
                  value={username}
                  onChange={e => setUsername(e.target.value)}
                  placeholder="Username"
                />
                <input
                  className="cqp-select"
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="Password"
                />
              </div>
              <button
                className="cqp-toggle-all"
                onClick={handleConnect}
                disabled={connecting}
                style={{ marginTop: 8, width: '100%' }}
              >
                {connecting ? 'Connecting...' : 'Connect'}
              </button>
            </>
          ) : (
            <>
              <div style={{
                background: 'var(--success-bg, #f0fdf4)',
                border: '1px solid var(--success-border, #86efac)',
                borderRadius: 6, padding: '6px 10px',
                fontSize: 12, color: 'var(--success-text, #166534)'
              }}>
                ● Connected to <strong>{database}</strong>
              </div>
              <button
                className="cqp-toggle-all"
                onClick={handleDisconnect}
                style={{ marginTop: 6, width: '100%' }}
              >
                Disconnect
              </button>
            </>
          )}
        </div>

        {/* Table Selector */}
        {tables.length > 0 && (
          <div className="cqp-section">
            <div
              className="cqp-section-label"
              style={{ cursor: 'pointer', display: 'flex', justifyContent: 'space-between' }}
              onClick={() => setShowTables(s => !s)}
            >
              <span>Tables ({selTables.length}/{tables.length})</span>
              {showTables ? <ChevronUp size={13} /> : <ChevronDown size={13} />}
            </div>
            {showTables && (
              <>
                <button className="cqp-toggle-all" onClick={toggleAll}>
                  {selTables.length === tables.length ? 'Deselect all' : 'Select all'}
                </button>
                <div className="cqp-checklist">
                  {tables.map(t => (
                    <label key={t} className={`cqp-check-item ${selTables.includes(t) ? 'on' : ''}`}>
                      <input
                        type="checkbox"
                        checked={selTables.includes(t)}
                        onChange={() => toggleTable(t)}
                      />
                      {selTables.includes(t) ? <CheckSquare size={13} /> : <Square size={13} />}
                      <span>{t}</span>
                    </label>
                  ))}
                </div>
                {selTables.length > 1 && (
                  <div style={{
                    fontSize: 11, color: 'var(--accent)',
                    marginTop: 4, paddingLeft: 4
                  }}>
                    ⚡ {selTables.length} tables — auto JOIN enabled
                  </div>
                )}
              </>
            )}
          </div>
        )}

        {/* Suggestions */}
        <div className="cqp-section cqp-suggestions">
          <div className="cqp-section-label">
            <Sparkles size={11} /> Suggestions
          </div>
          {SAMPLES.map(s => (
            <button
              key={s}
              className="cqp-suggestion"
              onClick={() => { setInput(s); textareaRef.current?.focus(); }}
            >
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* ── Right Chat Panel ── */}
      <div className="cqp-right">
        <div className="cqp-chat-header">
          <Database size={15} />
          <span>MySQL Chat</span>
          <Badge color="blue" style={{ marginLeft: 'auto' }}>
            {connected ? database : 'No connection'}
          </Badge>
        </div>

        <div className="cqp-messages">
          {history.length === 0 && !loading && (
            <div className="cqp-welcome">
              <Database size={28} />
              <div className="cqp-welcome-title">Ask your MySQL database anything</div>
              <div className="cqp-welcome-sub">
                {connected
                  ? 'Type a question below or pick a suggestion on the left'
                  : 'Connect to a MySQL database using the panel on the left'}
              </div>
            </div>
          )}

          {history.map((msg, i) => (
            <div key={i} className={`cqp-msg cqp-msg-${msg.type}`}>
              {msg.type === 'user' && (
                <div className="cqp-bubble-user">{msg.content}</div>
              )}
              {msg.type === 'result' && (
                <div className="cqp-bubble-result">
                  <ResultsPanel
                    key={`${i}-${msg.question}`}
                    result={msg.content}
                    question={msg.question}
                  />
                </div>
              )}
              {msg.type === 'error' && (
                <div className="cqp-bubble-result">
                  <Alert type="error">{msg.content}</Alert>
                </div>
              )}
            </div>
          ))}

          {loading && (
            <div className="cqp-msg cqp-msg-result">
              <div className="cqp-bubble-result cqp-typing">
                <div className="cqp-dot" />
                <div className="cqp-dot" />
                <div className="cqp-dot" />
                <span>Running MySQL query...</span>
              </div>
            </div>
          )}

          <div ref={chatEndRef} />
        </div>

        {error && (
          <div className="cqp-input-error">
            <Alert type="error" onClose={() => setError('')}>{error}</Alert>
          </div>
        )}

        <div className="cqp-input-bar">
          <textarea
            ref={textareaRef}
            className="cqp-textarea"
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={onKey}
            placeholder={connected
              ? "Ask anything about your MySQL data... (Enter to send)"
              : "Connect to a MySQL database first..."}
            rows={1}
            disabled={!connected || loading}
          />
          <button
            className="cqp-send-btn"
            onClick={send}
            disabled={loading || !input.trim() || !connected}
          >
            <Send size={15} />
          </button>
        </div>
      </div>
    </div>
  );
}
